import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Progress } from 'antd';
import 'antd/dist/reset.css';

const lessonData = {
  // 保持原有的lessonData结构不变
  1: {
    videoUrl: "https://www.youtube.com/embed/wtCDiS-mZQQ",
    quiz: [
      // ...保持原有quiz数据
    ]
  },
  // ...其他课程数据
};

export default function VideoPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const currentId = parseInt(id || "1");
  const maxLessonId = Object.keys(lessonData).length;
  const nextId = currentId + 1 > maxLessonId ? 1 : currentId + 1;

  const { videoUrl, quiz } = lessonData[currentId] || lessonData[1];
  const [answers, setAnswers] = useState(Array(quiz.length).fill(null));
  const [submitted, setSubmitted] = useState(false);
  const [aiHelpIndex, setAiHelpIndex] = useState(null);

  // 保持原有的handleOptionChange和handleSubmit函数不变
  const handleOptionChange = (index, option) => {
    const newAnswers = [...answers];
    newAnswers[index] = option;
    setAnswers(newAnswers);
  };

  const handleSubmit = () => {
    setSubmitted(true);
    setAiHelpIndex(null);
  };

  const score = answers.reduce((acc, cur, idx) => {
    return cur === quiz[idx].answer ? acc + 2 : acc;
  }, 0);

  return (
    <div className="content-card"> {/* 使用全局蓝色背景卡片 */}
      <div style={styles.container}>
        <h2 style={styles.title}>📹 Lesson {currentId} - Watch & Quiz</h2>

        {/* 视频区域 */}
        <div style={styles.videoWrapper}>
          <iframe
            width="100%"
            height="315"
            src={videoUrl}
            title={`Lesson ${currentId}`}
            frameBorder="0"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
          ></iframe>
        </div>

        {/* 问题区 - 保持原有功能 */}
        <div style={styles.quizSection}>
          {quiz.map((q, index) => (
            <div key={index} style={styles.questionBlock}>
              <p><strong>{q.question}</strong></p>
              {q.options.map((opt, optIdx) => (
                <label key={optIdx} style={styles.option}>
                  <input
                    type="radio"
                    name={`question-${index}`}
                    value={optIdx}
                    disabled={submitted}
                    checked={answers[index] === optIdx}
                    onChange={() => handleOptionChange(index, optIdx)}
                    style={styles.radioInput}
                  />
                  {opt}
                </label>
              ))}
              {submitted && answers[index] !== q.answer && (
                <p style={styles.wrongAnswer}>❌ Wrong answer</p>
              )}
              <button
                style={styles.helpButton}
                onClick={() => setAiHelpIndex(index)}
                disabled={submitted && answers[index] === q.answer}
              >
                🤖 Ask AI for help
              </button>
              {aiHelpIndex === index && (
                <div style={styles.aiResponse}>
                  <p><strong>AI:</strong> {q.help}</p>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* 提交与导航 - 保持原有功能 */}
        {!submitted ? (
          <button onClick={handleSubmit} style={styles.submitButton}>
            Submit
          </button>
        ) : (
          <p style={styles.score}>Your score: {score} / {quiz.length * 2}</p>
        )}

        <button
          onClick={() => navigate(`/video/${nextId}`)}
          style={styles.nextButton}
        >
          ▶️ Next Lesson →
        </button>
      </div>
    </div>
  );
}

// 新的蓝色主题样式
const styles = {
  container: {
    padding: '1.5em',
    fontFamily: 'Arial, sans-serif',
    maxWidth: '800px',
    margin: '0 auto',
  },
  title: {
    textAlign: 'center',
    color: '#00796b', // 蓝色系标题
    marginBottom: '1.5em',
    fontSize: '1.5em'
  },
  videoWrapper: {
    marginBottom: '2em',
    borderRadius: '10px',
    overflow: 'hidden',
    boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
    backgroundColor: '#f5fdff' // 浅蓝背景
  },
  quizSection: {
    marginBottom: '1.5em'
  },
  questionBlock: {
    marginBottom: '1.5em',
    background: '#f0f8ff', // 浅蓝背景
    padding: '1em',
    borderRadius: '8px',
    border: '1px solid #b0c4de' // 蓝色边框
  },
  option: {
    display: 'block',
    margin: '0.8em 0',
    padding: '0.8em',
    background: '#fff',
    borderRadius: '6px',
    cursor: 'pointer',
    transition: 'all 0.2s',
    ':hover': {
      background: '#e1f5fe' // 悬停浅蓝
    }
  },
  radioInput: {
    marginRight: '0.8em'
  },
  wrongAnswer: {
    color: '#d32f2f',
    fontStyle: 'italic',
    marginTop: '0.5em'
  },
  helpButton: {
    marginTop: '0.5em',
    padding: '0.4em 1em',
    backgroundColor: '#4fb3bf', // 蓝色按钮
    color: '#fff',
    border: 'none',
    borderRadius: '5px',
    cursor: 'pointer',
    transition: 'all 0.2s',
    ':hover': {
      backgroundColor: '#0288d1' // 深蓝悬停
    }
  },
  aiResponse: {
    marginTop: '0.8em',
    padding: '0.8em',
    background: '#e1f5fe',
    borderRadius: '6px',
    borderLeft: '3px solid #0288d1'
  },
  submitButton: {
    width: '100%',
    padding: '0.8em',
    backgroundColor: '#4fb3bf', // 蓝色按钮
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    fontSize: '1em',
    cursor: 'pointer',
    margin: '1em 0',
    transition: 'all 0.2s',
    ':hover': {
      backgroundColor: '#0288d1' // 深蓝悬停
    }
  },
  score: {
    fontWeight: 'bold',
    fontSize: '1.2em',
    textAlign: 'center',
    color: '#00796b', // 蓝色系
    margin: '1.5em 0'
  },
  nextButton: {
    display: 'block',
    margin: '1.5em auto 0',
    padding: '0.8em 1.5em',
    backgroundColor: '#4fb3bf', // 蓝色按钮
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    fontSize: '1em',
    cursor: 'pointer',
    transition: 'all 0.2s',
    ':hover': {
      backgroundColor: '#0288d1' // 深蓝悬停
    }
  }
};
